const raw = ($input.item.json.domain || $input.item.json.raw || '').toString();

if (!raw.trim()) {
  return { json: { domain: '', valid: false, error: 'Zadejte doménu' } };
}

// Split on commas, semicolons, spaces, newlines — take first non-empty token
const tokens = raw.split(/[,;\s\n]+/).map(s => s.trim()).filter(Boolean);
const token = tokens[0] || '';

// If it's an email, extract domain part
let candidate = token.includes('@') ? token.split('@')[1] : token;

// Strip protocol, www, paths, query params
candidate = candidate
  .replace(/^https?:\/\//i, '')
  .replace(/^www\./i, '')
  .split(/[\/?#]/)[0]
  .trim()
  .toLowerCase();

// Validate: must have at least one dot, valid domain chars
if (!candidate || !/^[a-z0-9.-]+\.[a-z]{2,}$/.test(candidate)) {
  return { json: { domain: '', valid: false, error: 'Neplatná doména: ' + token } };
}

return { json: { domain: candidate, valid: true } };
